member.example:
Bind the TMP_Text content to a localization table entry using a serialized binder field — the target TMP_Text is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private TextLocalizationEntryBinder _label;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public string _label; // bound value is used as the table entry key
    }


Bind the TMP_Text content to a localization entry by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_Text _target;
        
        private TextLocalizationEntryBinder Label =>
            new(_target, entry: "ui_label_key");
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public string _label;
    }

Switch the TMP_Text localization entry between two keys using a serialized binder field — the target TMP_Text is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private TextLocalizationEntrySwitcherBinder _isActive;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isActive;
    }


Switch the TMP_Text localization entry between two keys by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_Text _target;
        
        private TextLocalizationEntrySwitcherBinder IsActive => new(
            _target, trueValue: "ui_active_key", falseValue: "ui_inactive_key");
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isActive;
    }
